// 조회
scwin.f_Retrieve = async function () {
  // validation check
  if (!(await $c.gus.cfValidate($p, [ed_homeClntNo]))) {
    return;
  }

  // 조회시작일자가 더 클경우 체크
  if (!(await $c.gus.cfIsAfterDate($p, ed_qryConDtFm.getValue(), ed_qryConDtTo.getValue()))) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
    return;
  }
  if (acb_qryDtConKnd.getValue() == "CERTI") {
    let e = await $c.sbm.execute($p, sbm_retrieve);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
      scwin.sbm_retrieve_submitdone(e);
    }
  } else if (acb_qryDtConKnd.getValue() == "SPPLY" || acb_qryDtConKnd.getValue() == "POST") {
    let e = await $c.sbm.execute($p, sbm_eachSellingEvidenceList);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
      scwin.sbm_eachSellingEvidenceList_submitdone(e);
    }
  }
};

// 하단그리드 조회
scwin.f_DetailRetrieve = async function (row) {
  ds_condition_con.insertRow(0);
  ds_condition_con.setRowPosition(0);
  ds_condition_con.setCellData(0, "slipNo", ds_out.getCellData(row, "slipNo"));
  let e = await $c.sbm.execute($p, sbm_detail_retrieve);
  if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
    scwin.sbm_detail_retrieve_submitdone(e);
  }
};

// 조회조건 Clear
scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, tbl_search, null);
  ed_qryConDtFm.setValue(scwin.vQryStDt);
  ed_qryConDtTo.setValue(scwin.vQryEndDt);
  acb_qryDtConKnd.setValue("CERTI");
  acb_taxnClsCd.setValue("01");
  ed_homeClntNo.focus();
};

// 저장
scwin.f_Save = async function () {
  if (ds_out.getRowCount() < 1 || ds_detail.getRowCount() < 1) {
    return;
  }
  $c.gus.cfCopyDataSetHeader($p, ds_out, ds_saveOut);
  var transRow;
  var chkCnt = 0;
  for (var i = 0; i < ds_out.getRowCount(); i++) {
    if (ds_out.getCellData(i, "choice") == "T") {
      if (ds_out.getCellData(i, "spplyDt") == null || ds_out.getCellData(i, "spplyDt") == "") {
        await $c.gus.cfAlertMsg($p, "청구세금계산서 내역의 " + (i + 1) + "번째 데이터에 공급일자는 필수입력 항목입니다.");
        return;
      }
      if (ds_out.getCellData(i, "slipDt") == null || ds_out.getCellData(i, "slipDt") == "") {
        await $c.gus.cfAlertMsg($p, "청구세금계산서 내역의 " + (i + 1) + "번째 데이터에 전표일자는 필수입력 항목입니다.");
        return;
      }
      if (ds_out.getCellData(i, "goods") == null || ds_out.getCellData(i, "goods") == "") {
        await $c.gus.cfAlertMsg($p, "청구세금계산서 내역의 " + (i + 1) + "번째 데이터에 품명은 필수입력 항목입니다.");
        return;
      }

      // 세금계산서거 발행되었으면....
      if (ds_out.getCellData(i, "slipNo") != null && ds_out.getCellData(i, "slipNo") != "") {
        await $c.gus.cfAlertMsg($p, "청구세금계산서 내역의 " + (i + 1) + "번째 데이터는 매출증빙 내역이 있는 자료입니다.\n일괄저장 할 수 없습니다.");
        return;
      }
      transRow = ds_out.getRowJSON(i);
      var rowIndex = ds_saveOut.insertRow();
      ds_saveOut.setRowJSON(rowIndex, transRow, true);
      ds_saveOut.setCellData(rowIndex, "curRow", i);
      chkCnt++;
    }
  }
  scwin.isFilter = false;
  $c.gus.cfCopyDataSetHeader($p, ds_detail, ds_saveDetail);
  var transRow2;
  var chkCnt2 = 0;
  for (var i = 0; i < ds_detail.getRowCount(); i++) {
    if (ds_detail.getCellData(i, "choice") == "T") {
      if (ds_out.getCellData(ds_out.getMatchedIndex('bilgClntNo', ds_detail.getCellData(i, "bilgClntNo")), "choice") == "T") {
        transRow2 = ds_detail.getRowJSON(i);
        var rowIndex = ds_saveDetail.insertRow();
        ds_saveDetail.setRowJSON(rowIndex, transRow2, true);
        chkCnt2++;
      }
    }
  }
  scwin.isFilter = true;
  if (chkCnt < 1 || chkCnt2 < 1) {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ["저장할 자료"]);
    return;
  }
  let saveChk = await $c.win.confirm($p, MSG_CM_CRM_001);
  if (!saveChk) {
    return;
  }
  let e = await $c.sbm.execute($p, sbm_save);
  if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
    scwin.sbm_save_submitdone(e);
  }
};

// 팝업창 처리
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
  // 선언부
  var rtnList = new Array(); // 공통POP-UP -> 요청화면
  switch (disGubun) {
    case 1:
      // 소속거래처    
      udc_homeClntNo.setSelectId("retrieveSubsidaryClntListJa");
      rtnList = await udc_homeClntNo.cfCommonPopUpAsync('' // XML상의 SELECT ID
      , pCode // 화면에서의 ??? Code Element의	Value
      , pName // 화면에서의 ??? Name Element의	Value
      , pClose // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
      , '5' // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
      , null // Title순서
      , '150,170' // 보여주는 각 컬럼들의 폭
      , null // 컬럼중에서 숨기는	컬럼 지정
      , null // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
      , null // POP-UP뛰을때 원도우의	사용자 정의	폭
      , null // POP-UP뛰을때 우도우의	사용자 정의	높이
      , null // 윈도우 위치 Y좌표
      , null // 윈도우 위치 X좌표
      , null // 중복체크여부	("F")
      , pAllSearch // 전체검색허용여부	("F")
      , "소속거래처,거래처코드,거래처명" // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
      );
      if (rtnList != null) {
        $c.gus.cfSetReturnValue($p, rtnList, ed_homeClntNo, ed_homeClntNm);
      }
      break;
    case 2:
      // 차량번호
      udc_vehclNo.setSelectId("retrieveSubsidaryVehclList");
      rtnList = await udc_vehclNo.cfCommonPopUpAsync('' // XML상의 SELECT ID
      , pCode // 화면에서의 ??? Code Element의  Value
      , pName // 화면에서의 ??? Name Element의  Value
      , pClose // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
      , null // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
      , null // Title순서  
      , null // 보여주는 각 컬럼들의 폭    
      , null // 컬럼중에서 숨기는    컬럼 지정   
      , null // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
      , "400" // POP-UP뛰을때 원도우의   사용자 정의  폭
      , null // POP-UP뛰을때 우도우의   사용자 정의  높이  
      , null // 윈도우 위치 Y좌표   
      , null // 윈도우 위치 X좌표
      , null // 중복체크여부   ("F")
      , pAllSearch // 전체검색허용여부 ("F")
      , "차량번호,차량단축코드,차량번호" // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
      );
      if (rtnList != null) {
        $c.gus.cfSetReturnValue($p, rtnList, ed_vehclNoCd, ed_vehclNo);
      }
      break;
    default:
      break;
  }
};

// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) return;

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) {
    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  } else {
    // inObj가 코드명 필드일 경우 팝업
    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
  }
};

// 세금계산서 출력
scwin.f_Print = async function () {
  var param = "";
  var printCnt = 0;
  for (var i = 0; i < ds_out.getRowCount(); i++) {
    if (ds_out.getCellData(i, "printChk") == "T") {
      param = param + ",TO_CHAR(" + ds_out.getCellData(i, "sellVatNo") + ")"; // 계산서번호
      printCnt++;
    }
  }
  if (printCnt == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ["발행할 세금계산서"]); // @을(를) 선택하십시오.
    return;
  }
  const data = {
    reportName: "/ac/fi/taxbiz/vatctrl/fi_401_01_09p_2.ozr",
    odiName: "fi_401_01_09p",
    odiParam: {
      pchsSellCls: param.substring(1)
    },
    viewerParam: {
      mode: "preview"
    },
    formParam: {}
  };
  await scwin.openPopup(data);
};
