scwin.ds_outSellingEvidenceList_ondataload = function () {
  debugger;
  for (var i = 0; i < ds_outSellingEvidenceList.getRowCount(); i++) {
    var targetIndex = ds_outSellingEvidenceList.getCellData(i, "curRow");
    ds_out.setCellData(targetIndex, "sellVatNo", ds_outSellingEvidenceList.getCellData(i, "sellVatNo"));
    ds_out.setCellData(targetIndex, "slipNo", ds_outSellingEvidenceList.getCellData(i, "slipNo"));
    ds_out.setCellData(targetIndex, "dcsnClsNm", ds_outSellingEvidenceList.getCellData(i, "dcsnClsNm"));
    if (i == rowcnt) {
      ds_out.setRowPosition(targetIndex);
      ds_out.setCellData(targetIndex, "choice", "F");

      //ds_out.ColumnProp('choice', 'Edit') = "None";
      gr_detail.setColumnReadOnly('choice', true);

      //gr_detail.ColumnProp('choice', 'Show') = "false";
      gr_detail.setColumnVisible('choice', false);
    }
  }
};

